export class Common{constructor(){this.recCourse=document.getElementById("recommended-courses-name"),this.otherCourse=document.getElementById("other-courses"),this.menu=document.querySelector(".menu"),this.menuOpenClose=document.querySelector(".menu-open-close"),this.init()}init(){this.menuOpenClose.onclick=()=>{"block"===this.menu.style.display?this.menu.style.display="none":this.menu.style.display="block"},this.recCourse.onclick=()=>{location.href="#/choice/"},this.otherCourse.onclick=()=>{location.href="#/choice/"}}}